css.value:
.page-content {
  --page-primary-light-color: rgb(243, 242, 239);
}

.page-sidebar-background {
  background-color: var(--page-primary-light-color);
}



.page-header .basics-items {
  border: none;
  padding: 0;
  order: 3
}
.page-header .page-picture {
  order: 2
}

.page-header .text-center {
  text-align: left ;
}

.page-header .basics-name {
  font-size: 2.8em;
  line-height: 1;
  color: #17535B;
}

.page-header .basics-headline {
  font-size: 1.7em;
  color: #17535B;
  font-style: italic;
}

.page-section > h6 {
  background-color: var(--page-primary-color);
  border: none;
  color: var(--page-secondary-color);
  text-align: center;
  margin-bottom: 0.8em;
}

.section-item-header {
  padding-bottom: 0.2em;
}

.experience-item-roles {
  border-left: 1px solid var(--page-primary-color);
  padding-left: 10pt;
  margin-left: 2pt;
}

.experience-item-roles li {
  margin-inline-start: 1.5rem;
}

.basics-items svg, .basics-items i {
  fill: var(--page-secondary-color);;
  color: var(--page-secondary-color) !important;
}
.basics-items .ph-linkedin-logo {
  position: relative;
  top: 3px;
}

.basics-items .basics-item-email svg {
  position: relative;
  top: 2px;        
}

.basics-items .ph-github-logo {
  position: relative;
  top: 2px;
}
.basics-items  .basics-item-location svg {
  position: relative;
  bottom: 1px;
}
.basics-items .basics-item-location{
  order: 10
}
.experience-item-role > div:first-child {
  grid-template-columns: repeat(1, minmax(0, 1fr));
}

.experience-item-role-position {
  font-weight: 600;
}

.page-1 .section-item-experience:nth-child(2) .experience-item-header div, .page-1 .section-item-experience:nth-child(2) .experience-item-header span {
  display: block;
  text-align: left;
}

.page-1 .section-item-experience:nth-child(3) .experience-item-header div, .page-1 .section-item-experience:nth-child(3) .experience-item-header span {
  display: block;
  text-align: left;
}

.page-section-019d7e72-1597-70a4-ad1f-67f7b40a67af {
  margin-bottom: 0.3rem;
}
